const WMO = { 0:'Ceu limpo',1:'Predom. limpo',2:'Parc. nublado',3:'Nublado',45:'Nevoa',48:'Nevoa c/ geada',51:'Garoa fraca',53:'Garoa',55:'Garoa forte',61:'Chuva fraca',63:'Chuva',65:'Chuva forte',66:'Chuva congelante',67:'Chuva congelante forte',71:'Neve fraca',73:'Neve',75:'Neve forte',77:'Graos de neve',80:'Aguaceiros fracos',81:'Aguaceiros',82:'Aguaceiros fortes',85:'Aguaceiros de neve',86:'Aguaceiros de neve fortes',95:'Trovoada',96:'Trovoada c/ granizo',99:'Trovoada forte c/ granizo' };

function buildChecklist(f){
  const out = [];
  const { temp_max:tmax, temp_min:tmin, precip_prob:prob, precip_mm:mm, uv_index:uv, weather_code:code } = f;
  if (tmin != null && tmin < 5) out.push('casaco pesado + touca e luvas');
  else if (tmin != null && tmin < 10) out.push('casaco quente / blusa de frio');
  else if (tmin != null && tmin < 15) out.push('casaco leve para a noite');
  if (tmax != null && tmax >= 30) out.push('roupas leves e respiraveis','bone ou chapeu','garrafa de agua (hidratacao)');
  else if (tmax != null && tmax >= 25) out.push('roupas leves');
  if ((prob != null && prob >= 50) || (mm != null && mm >= 1)) out.push('guarda-chuva ou capa de chuva');
  else if (prob != null && prob >= 30) out.push('guarda-chuva dobravel (pode chover)');
  if (uv != null && uv >= 6) out.push('protetor solar FPS alto','oculos de sol');
  else if (uv != null && uv >= 3) out.push('protetor solar');
  if ([71,73,75,77,85,86].includes(code)) out.push('roupa de neve / calcado impermeavel');
  if ([95,96,99].includes(code)) out.push('capa de chuva (risco de trovoada)');
  if (out.length === 0) out.push('roupas confortaveis para clima ameno');
  return out;
}

const stop = $('Split Out').item.json;
const d = $json.daily || {};
const f = {
  temp_max: (d.temperature_2m_max||[])[0] ?? null,
  temp_min: (d.temperature_2m_min||[])[0] ?? null,
  precip_mm: (d.precipitation_sum||[])[0] ?? null,
  precip_prob: (d.precipitation_probability_max||[])[0] ?? null,
  uv_index: (d.uv_index_max||[])[0] ?? null,
  weather_code: (d.weather_code||[])[0] ?? null,
};
const weather = WMO[f.weather_code] || ('codigo ' + f.weather_code);
return { json: {
  city: stop.city || stop.name || '', date: (d.time||[])[0] ?? stop.date,
  lat: stop.lat, lon: stop.lon,
  temp_min_c: f.temp_min, temp_max_c: f.temp_max,
  precip_mm: f.precip_mm, precip_prob_pct: f.precip_prob,
  uv_index_max: f.uv_index, weather_code: f.weather_code, weather,
  source: 'open-meteo', checklist: buildChecklist(f)
} };
